import { TokenBucket } from '../src/rateLimiter';

describe('TokenBucket', () => {
  test('allows requests within burst limit', () => {
    const limiter = new TokenBucket({ rate: 10, burst: 5 });
    for (let i = 0; i < 5; i++) {
      expect(limiter.allow()).toBe(true);
    }
  });

  test('rejects when tokens exhausted', () => {
    const limiter = new TokenBucket({ rate: 10, burst: 3 });
    limiter.allow(); // 1
    limiter.allow(); // 2
    limiter.allow(); // 3
    expect(limiter.allow()).toBe(false); // exhausted
  });

  test('refills tokens over time', () => {
    const limiter = new TokenBucket({ rate: 1000, burst: 2 });
    limiter.allow();
    limiter.allow();
    expect(limiter.allow()).toBe(false);

    // Simulate time passing (1ms = 1 token at rate 1000/sec)
    jest.spyOn(Date, 'now').mockReturnValue(Date.now() + 2);
    expect(limiter.allow()).toBe(true);
    jest.restoreAllMocks();
  });

  test('tokens do not exceed burst', () => {
    const limiter = new TokenBucket({ rate: 1000, burst: 3 });
    // Wait a long time — should still cap at burst
    jest.spyOn(Date, 'now').mockReturnValue(Date.now() + 10000);
    for (let i = 0; i < 3; i++) {
      expect(limiter.allow()).toBe(true);
    }
    expect(limiter.allow()).toBe(false);
    jest.restoreAllMocks();
  });

  test('returns remaining tokens count', () => {
    const limiter = new TokenBucket({ rate: 10, burst: 5 });
    expect(limiter.remaining()).toBe(5);
    limiter.allow();
    expect(limiter.remaining()).toBe(4);
  });
});

export interface TokenBucketOptions {
  rate: number;   // tokens per second
  burst: number;  // max tokens (bucket capacity)
}

export class TokenBucket {
  private tokens: number;
  private readonly rate: number;
  private readonly burst: number;
  private lastRefill: number;

  constructor(options: TokenBucketOptions) {
    this.rate = options.rate;
    this.burst = options.burst;
    this.tokens = options.burst; // start full
    this.lastRefill = Date.now();
  }

  allow(): boolean {
    this.refill();
    if (this.tokens >= 1) {
      this.tokens -= 1;
      return true;
    }
    return false;
  }

  remaining(): number {
    this.refill();
    return Math.floor(this.tokens);
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = (now - this.lastRefill) / 1000; // seconds
    this.tokens = Math.min(this.burst, this.tokens + elapsed * this.rate);
    this.lastRefill = now;
  }
}
